class AccountUtilityEnergyUseTableComponent {
    constructor(dashboardService, utilityMeterDataDbService, facilityDbService, accountdbService) {
        this.dashboardService = dashboardService;
        this.utilityMeterDataDbService = utilityMeterDataDbService;
        this.facilityDbService = facilityDbService;
        this.accountdbService = accountdbService;
    }
    ngOnInit() {
        let lastMonthYear = this.dashboardService.getLastMonthYear();
        this.lastMonthsDate = new Date(lastMonthYear.lastMonthYear, lastMonthYear.lastMonth);
        this.selectedAccountSub = this.accountdbService.selectedAccount.subscribe(val => {
            if (val) {
                this.accountEnergyUnit = val.energyUnit;
            }
        });
        this.accountMeterDataSub = this.utilityMeterDataDbService.accountMeterData.subscribe(val => {
            if (val && val.length != 0) {
                this.setUsageValues();
            }
            else {
                this.utilityUsageSummaryData = {
                    utilitySummaries: new Array(),
                    total: {
                        lastBillDate: undefined,
                        previousMonthEnergyUse: 0,
                        previousMonthEnergyCost: 0,
                        averageEnergyUse: 0,
                        averageEnergyCost: 0,
                        utility: undefined
                    }
                };
            }
        });
    }
    ngOnDestroy() {
        this.accountMeterDataSub.unsubscribe();
        this.selectedAccountSub.unsubscribe();
    }
    setUsageValues() {
        let accountFacilities = this.facilityDbService.accountFacilities.getValue();
        this.utilityUsageSummaryData = this.dashboardService.getFacilitiesUtilityUsageSummaryData(accountFacilities, true);
    }
}
