class EnergySourceComponent {
    constructor(accountdbService, facilitydbService, utilityMeterDatadbService, utilityMeterdbService, editMeterFormService) {
        this.accountdbService = accountdbService;
        this.facilitydbService = facilitydbService;
        this.utilityMeterDatadbService = utilityMeterDatadbService;
        this.utilityMeterdbService = utilityMeterdbService;
        this.editMeterFormService = editMeterFormService;
        // energyFinalUnit: string;
        this.page = 1;
        this.itemsPerPage = 10;
        this.selectedFacilityName = 'Facility';
        this.addOrEdit = 'add';
    }
    ngOnInit() {
        this.meterListSub = this.utilityMeterdbService.facilityMeters.subscribe(meters => {
            this.meterList = meters;
        });
        this.selectedFacilitySub = this.facilitydbService.selectedFacility.subscribe(facility => {
            if (facility) {
                this.selectedFacilityName = facility.name;
            }
        });
    }
    ngOnDestroy() {
        this.meterListSub.unsubscribe();
        this.selectedFacilitySub.unsubscribe();
    }
    // Close menus when user clicks outside the dropdown
    documentClick() {
        this.meterMenuOpen = null;
    }
    meterToggleMenu(index) {
        if (this.meterMenuOpen === index) {
            this.meterMenuOpen = null;
        }
        else {
            this.meterMenuOpen = index;
        }
    }
    addMeter() {
        let selectedFacility = this.facilitydbService.selectedFacility.getValue();
        let selectedAccount = this.accountdbService.selectedAccount.getValue();
        this.addOrEdit = 'add';
        this.editMeter = this.utilityMeterdbService.getNewIdbUtilityMeter(selectedFacility.id, selectedAccount.id);
    }
    meterExport() {
        const replacer = (key, value) => value === null ? '' : value; // specify how you want to handle null values here
        const header = Object.keys(this.meterList[0]);
        let csvData = this.meterList.map(row => header.map(fieldName => JSON.stringify(row[fieldName], replacer)).join(','));
        csvData.unshift(header.join(','));
        let csvBlob = csvData.join('\r\n');
        //Download the file as CSV
        var downloadLink = document.createElement("a");
        var blob = new Blob(["\ufeff", csvBlob]);
        var url = URL.createObjectURL(blob);
        downloadLink.href = url;
        downloadLink.download = "VerifiMeterDump.csv";
        document.body.appendChild(downloadLink);
        downloadLink.click();
        document.body.removeChild(downloadLink);
    }
    onPageChange(pageNum) {
        this.pageSize = this.itemsPerPage * (pageNum - 1);
    }
    changePagesize(num) {
        this.itemsPerPage = num;
        this.onPageChange(this.page);
    }
    closeImportWindow() {
        this.importWindow = false;
    }
    showImportWindow() {
        this.importWindow = true;
    }
    selectEditMeter(meter) {
        this.addOrEdit = 'edit';
        this.editMeter = meter;
    }
    closeEditMeter() {
        this.editMeter = undefined;
    }
    deleteMeter() {
        //delete meter
        this.utilityMeterdbService.deleteIndex(this.meterToDelete.id);
        //delete meter data
        this.utilityMeterDatadbService.deleteMeterDataByMeterId(this.meterToDelete.id);
        this.cancelDelete();
    }
    selectDeleteMeter(meter) {
        this.meterToDelete = meter;
    }
    cancelDelete() {
        this.meterToDelete = undefined;
        this.meterMenuOpen = null;
    }
    isMeterInvalid(meter) {
        let form = this.editMeterFormService.getFormFromMeter(meter);
        return form.invalid;
    }
}
